#!/bin/bash
LOG_FILE=/var/log/hls-proxy.log
ERROR="ERROR Request failed, no retry left: Exception: connect ENETUNREACH"

if cat $LOG_FILE | grep -q "$ERROR"; then
    echo "Unhealthy container. exit 1"   
    > $LOG_FILE
    exit 1
else
	exit 0
fi

#Example error line:
#ERROR Request failed, no retry left: Exception: connect ENETUNREACH 45.150.197.62:25461 - Local (0.0.0.0:0) http://45.150.197.62:25461/live/KjBJ8q0CVe/0aVuxftuB1/1085.m3u8?